openscad:
case_diameter = 40; // [20:1:80]
case_thickness = 8; // [4:1:15]
dial_thickness = 2; // [1:0.5:5]
marker_width = 2; // [1:0.5:4]
hand_length_h = 12; // [5:1:18]
hand_length_m = 16; // [8:1:20]
hand_width = 1.5; // [0.5:0.5:3]
$fn = 60;

module watch() {
    // Black case
    color("black")
    difference() {
        cylinder(h=case_thickness, d=case_diameter, center=true);
        translate([0,0,case_thickness/2 - dial_thickness])
            cylinder(h=dial_thickness+0.1, d=case_diameter-4, center=true);
    }

    // White dial
    color("white")
    translate([0,0,case_thickness/2 - dial_thickness/2])
        cylinder(h=dial_thickness, d=case_diameter-4, center=true);

    // Black hour markers
    color("black")
    for (i = [0:11]) {
        rotate([0,0,i*30])
        translate([case_diameter/2 - 5, 0, case_thickness/2 - dial_thickness/2 + 0.1])
            cube([marker_width, 1.2, dial_thickness], center=true);
    }

    // Black hands
    color("black") {
        // Hour hand (pointing ~10 o'clock)
        rotate([0,0,300])
        translate([hand_length_h/2 - 2, 0, case_thickness/2 - dial_thickness/2 + 0.2])
            cube([hand_length_h, hand_width, 1], center=true);

        // Minute hand (pointing ~2 o'clock)
        rotate([0,0,60])
        translate([hand_length_m/2 - 2, 0, case_thickness/2 - dial_thickness/2 + 0.2])
            cube([hand_length_m, hand_width*0.8, 1], center=true);

        // Center pin
        translate([0,0,case_thickness/2 - dial_thickness/2 + 0.3])
            cylinder(h=1.2, d=3, center=true);
    }
}

watch();
